var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"좋아. 방금 꽤 나쁘지 않았어.","JPN":"よし、今のは悪くなかったわ。","ENG":"Okay, it was pretty good.","TWN":"很好，剛剛還不錯！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"한 번 더 이 느낌을 살려서…….","JPN":"もう一度、さっきの感じで……","ENG":"Let’s try this one more time...","TWN":"再熟悉一下這個感覺……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_OFFICE_QM","text":{"KOREA":"안 본 사이 실력이 상당히 느셨구만.","JPN":"見ない間に相当腕を上げましたね。","ENG":"Your skill has improved a lot since the last time I saw you.","TWN":"一段時間沒見，實力進步不少喔。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"이제는 정말 더 가르쳐 드릴 것도 없겠수다.","JPN":"もう教えることはなさそうです。","ENG":"It looks like you won’t need my teaching anymore.","TWN":"看來我已經沒什麼可以教你的囉。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아. 안녕하세요, 현수 씨.","JPN":"あ、こんにちは、ケンジさん。","ENG":"Oh, hello, Hyunsoo.","TWN":"喔！哈囉，賢秀。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"체육관에서 뵙는 건 오랜만이네요. 요즘도 일이 많이 바쁘신가 봐요.","JPN":"ジムでお会いするのは久しぶりですね。最近もお忙しいのですか？","ENG":"It’s been a while since I saw you last in the gym. You must be busy.","TWN":"上次在體育館見到你已經多久啦？你最近也很忙吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭐 변변찮은 회사 다니는 사람들이 다 그렇지.","JPN":"まあ、しがない会社員はみんなそうでしょう。","ENG":"You know how it is.","TWN":"哎呀～一般在公司上班不就這麼回事嗎？大家都差不多啦。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"야근에, 잔업에, 주말 출근까지…….","JPN":"夜勤に、残業、週末出勤……","ENG":"Working overtime, extra work, weekend work...","TWN":"平日加班啦，週末加班啦……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"정신 안 차리면 한 달이 어떻게 지나가는지도 모르거든.","JPN":"ぼけっとしてると、一か月なんて一瞬ですよ。","ENG":"I don’t even remember how the last month went by.","TWN":"常常一不注意，一個月咻一下就過去了呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하하. 이거, 오랜만에 보는 사람한테 너무 푸념만 늘어 놓는 것 같군.","JPN":"はは。久々に会ったというのに、愚痴ばかりですまないね。","ENG":"Oh, I’m boring you, aren’t I?","TWN":"哈哈，你看我真是的，我們這麼久沒見，一見面就一直跟你抱怨。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 회사원들은 어딜 가나 다 비슷비슷하죠.","JPN":"いえ、会社員なんてどこも似たようなものです。","ENG":"Not at all. I guess that’s just the life of an office worker.","TWN":"別這麼說，上班族的心情應該都差不多啦。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그래도 그 바쁜 와중에 검술 연습까지 하시고, 성실하시네요.","JPN":"でも、お忙しい中でも剣術の稽古をされているなんて、努力家なのですね。","ENG":"But still, I think it’s a great idea to work out, despite the busy schedule.","TWN":"不過你這麼忙還來練劍，很認真呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어떠신가요? 몸이 녹슬지 않게 하려면 움직여 줘야죠?","JPN":"どうです？　身体が怠けないようにするには、動くのが一番でしょ？","ENG":"So, how’s your practice going? Shall we spar?","TWN":"如何？要試試我是否寶刀未老嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L23_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"흐음……. 이제는 나보다 더 연습을 열심히 하시나 본데.","JPN":"うーん……今では私よりも稽古に励んでいるようですが。","ENG":"Oh, I see you’ve grown very passionate.","TWN":"嗯嗯……現在你可是練得比我還勤快呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"요즘 다시 재미를 붙였거든요. 계기는 이미지 메이킹이었지만요.","JPN":"最近また楽しいと思うようになったんです。きっかけはイメージメイキングでしたけど。","ENG":"Yes, it’s quite fun actually. Even though my initial motive was to build a positive image of myself.","TWN":"因為我最近又找回練劍的樂趣，雖然契機是因為要打造形象。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하하. 처음 본 날이 생각나는군.","JPN":"はは、初めて会った日のことを思い出します。","ENG":"Yeah, I remember your first day.","TWN":"哈哈，我想起我們第一次見面的時候。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"연습 상대가 되어 달라더니 다짜고짜 진검을 뽑아들었지.","JPN":"稽古の相手をしてくれと、いきなり本物の剣を抜いてきましたよね。","ENG":"You asked me to spar holding a real sword out of nowhere.","TWN":"我問你可不可以當我的練習對象，結果你二話不說就掏出一把貨真價實的劍。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부끄럽네요. 그 때는 용병이라면 다들 연습도 실전처럼 하는 줄 알았으니까요.","JPN":"お恥ずかしい。あの時は、傭兵はみんな稽古も実践のような形でやるものだと思っていましたので。","ENG":"That’s embarrassing. I thought mercenaries practiced with real weapons back then.","TWN":"真是不好意思，我當時候以為傭兵都是拿真的劍在練習的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그래서, 대답은?","JPN":"それで、返事は？","ENG":"So, spar with me?","TWN":"所以你的回答是？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"좋아. 까짓 거 한 판 하겠수다.","JPN":"いいですよ、やりましょう。","ENG":"Gladly.","TWN":"好！就來比劃一場吧！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"다만, 아무리 고등급 카운터라도 칼 한 자루로 밥 벌어먹고 사는 사람을 쉽게 꺾을 수는 없을 거요.","JPN":"ただ、いくら高ランクカウンターでも、剣一本で食ってる人間を打ちのめすのは簡単ではないと思いますよ。","ENG":"But I make a living with my sword; you won’t beat me easily even if you’re a high-grade Counter.","TWN":"不過，就算你是很厲害的制裁者，好歹我也是靠著一把劍闖蕩到現在，不要以為可以輕易打倒我喔！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"대단하군. 움직임도 찌르기도 저번보다 훨씬 더 정교해졌어.","JPN":"大したものだ。動きや突きも、この間よりずっと正確になっていますね。","ENG":"That was great. Your movements and attacks have grown very sophisticated.","TWN":"厲害！每個動作都比我還要俐落精準。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"취미로 배우다가 이 정도인가…….","JPN":"趣味でこれほどとは……","ENG":"You’re pretty hardcore for a hobbyist.","TWN":"說是學興趣的卻這麼厲害……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"재능이란 놈은 하여튼 불공평하군!","JPN":"才能ってやつは、本当に不公平極まりない！","ENG":"I hate talented people!","TWN":"有天賦的人真是不公平！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 이걸 꼭 배워야 할 수 있는 건가요?","JPN":"あら？　これは習わないとできないものなのでしょうか？","ENG":"What? Isn't it something you can do without learning?","TWN":"嗯？這是需要學的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"후훗. 정말로 재능 있는 사람을 못 보셨군요.","JPN":"ふふっ、本当に才能のある人に会ったことがないのですね。","ENG":"You haven’t seen real talent.","TWN":"呵呵，看來你還沒看過真正有天賦的人。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저 같은 건 오히려 평범한 축에 속하죠.","JPN":"私なんて、平凡な方ですよ。","ENG":"I’m just an ordinary person.","TWN":"像我這種的就只能被歸類到普通人而已。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"정말로 평범한 사람을 못 보셨나 보군.","JPN":"本当に平凡な人間を知らないのですね。","ENG":"You have no idea what ordinary means.","TWN":"看來你還沒看過真正的普通人。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하지만 누군지 궁금해졌수다.","JPN":"でも、気になってきました。","ENG":"But, I’m curious to see that *real talent*.","TWN":"不過還真有點好奇那個人是誰呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그렇게 젊은 나이에……","JPN":"そんな若くして……","ENG":"You climbed to the top of Alphatrix, where ordinary people aren’t even allowed...","TWN":"年紀輕輕的……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"평범한 사람은 문턱도 못 밟아 볼 알파트릭스 그룹에서 승승장구하신 분이…!","JPN":"平凡な人間は近づくこともできないアルファトリックスグループで、とんとん拍子に上り詰めた方が……","ENG":"At such a young age.","TWN":"可以在普通人，根本連門檻都跨不進的阿爾法崔克斯集團中，一路過關斬將…！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"칭찬을 아끼지 않는 분이 누군지!!","JPN":"そこまで絶賛する相手が誰なのか！！","ENG":"And you speak so highly of this person. Who could that be?!","TWN":"又不吝嗇讚美的人！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"크읏…!","JPN":"くうっ……！","ENG":"Hmph...!","TWN":"唔…！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……평범한 사람은 헤아릴 수조차 없는 분이죠.","JPN":"……私のような平凡な人間には雲の上の存在です。","ENG":"...She’s simply beyond ordinary.","TWN":"……當然是普通人猜不到的人囉！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어떤 상황에서도, 어떤 문제가 닥쳐도… 결국 실패하지 않을 테니까요.","JPN":"どんな状況で、どんな問題が起きようとも……必ず結果を出す方ですから。","ENG":"She’s someone who never fails, no matter what happens...","TWN":"因為她無論處在什麼情況，或是遇到什麼問題…都絕對不會失敗。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그럼 그렇게 완벽한 분을 댁이 왜 걱정하는 거요?","JPN":"それほど完璧なら、心配する必要なんてないのでは？","ENG":"Then why are you so worried about her?","TWN":"那麼完美的人，那你在擔心什麼呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"빈 틈!","JPN":"隙あり！","ENG":"You’re open!","TWN":"有機會！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"…으윽!","JPN":"……うぐっ！","ENG":"Ugh!","TWN":"…噢嗚！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"현수 씨?!","JPN":"ケンジさん！？","ENG":"Hyunsoo?!","TWN":"賢秀？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"죄송해요. 제가 무의식적으로 불을 일으켜서……","JPN":"すみません、私としたことが無意識に火を……","ENG":"I’m sorry, I didn’t mean to start the fire, I did it without thinking...","TWN":"很抱歉，我不自覺就用火……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"쿨럭, 당신 같은 고등급 카운터를 두 번 놀렸다간 재만 남겠어.","JPN":"ゲホッ、あなたのような高ランクカウンターを二度もからかったら、灰しか残らないでしょうね。","ENG":"*Cough* I won’t tease another high-grade Counter ever again. It’s too scary.","TWN":"咳咳，要是和你這種厲害的制裁者再多打一場，我可能會變成灰燼吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"괜찮으세요? 어디 다치지는 않으셨나요?","JPN":"大丈夫ですか？　お怪我はありませんか？","ENG":"Are you alright? Are you hurt?","TWN":"你還好嗎？有哪裡受傷嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"능력을 통제하지 못하다니……. 어떻게 이런 실수를…….","JPN":"この私が能力をコントロールし誤るなんて……","ENG":"I failed to control my power... This is just unthinkable...","TWN":"竟然沒控制好我的能力……犯下這種錯誤……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭘. 살짝 그을린 정도인데.","JPN":"なに、ちょっと焦げた程度です。","ENG":"Don’t worry, it’s just a little burn.","TWN":"沒事～就被燻黑一點點而已。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"댁 실력이 너무 좋아져서 나도 모르게 좀 흥분했군. 미안하게 됐수다.","JPN":"あなたの上達があまりにも早かったから、ついムキになってしまいました。こちらこそすみません。","ENG":"I got carried away because you were too good. I’m sorry about that.","TWN":"遇到厲害的對手，害我也不自覺地興奮起來，真是不好意思。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"전부터 생각했던 거지만, 현수 씨는 지금의 데이마인에는 아까운 인재라고 생각해요.","JPN":"前から思っていましたが、ケンジさんは今のデイマインには勿体ない人材です。","ENG":"To be honest, I don’t think Daymine deserves someone like you.","TWN":"我之前就有這種想法，你能力這麼好，待在現在的戴瑪因有點可惜，"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"현수 씨만 괜찮으시다면 제가 더 좋은 자리를 알아봐 드릴 수도 있는데… 어떠세요?","JPN":"ケンジさんさえよろしければ、私のほうでもっと待遇の良い仕事を紹介することもできますが……いかがですか？","ENG":"I can get you a better position if you wish. What do you say?","TWN":"如果你願意的話，我可以替你安排一個更好的位置…不知道你意下如何？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"스카우트 제안이라면 괜찮수다.","JPN":"スカウトなら結構です。","ENG":"Is that a job offer? No thanks.","TWN":"我還沒有要跳槽的打算。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"회사 사정이 나쁜 건 사실이지만, 내가 없으면 막 들어 온 애송이들을 봐 줄 사람이 없거든.","JPN":"会社の状況が悪いのは事実ですが、私がいなくなったら新人どもの面倒を見る人がいなくなるのでね。","ENG":"I know the company is not in good shape right now, but someone has to take care of the noobs.","TWN":"公司現在情況確實不好，但我不在的話，就沒人看著那些剛進來的小鬼。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"책임감도 좋지만 본인의 커리어 관리가 우선 아닌가요?","JPN":"責任感も大切ですが、まずはご自分のキャリアを優先するべきでは？","ENG":"Being responsible is a good thing, but you have to think about your career.","TWN":"有責任感是很好，但你不認為應該要以自己的事業為優先嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"다른 업계라면 그렇겠지. 이 바닥처럼 까딱하면 죽을 곳만 아니라면.","JPN":"他の業界ならそうかもしれません。ここみたいに、いつどこでくたばるかわからないとこじゃなければ。","ENG":"I would do if I was in some other business. But in this field, it is my life that’s at risk.","TWN":"如果我不是幹這行的話，幹我們這行隨時都可能喪命。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"은퇴나, 커리어 망치는 정도로 끝나면 다행이지.","JPN":"引退や、キャリアが台無しになるくらいで済めば御の字です。","ENG":"You’re lucky if you end up retired, or ruining your career.","TWN":"有命活到退休，或是毀掉事業，都還算是幸運。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭐가 됐든 비명횡사하는 것보단 나을 테니까.","JPN":"どっちにしろ、ぽっくり死んじまうよりはずっとマシでしょうから。","ENG":"That is much better than dying.","TWN":"因為不管怎麼樣都比橫死街頭好。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그러니, 적어도 팀원들이 자기 앞가림은 할 수 있게 해 줘야 제대로 된 어른 아니겠소?","JPN":"なので、少なくともチームの連中が一人前になるまでは見守るのが、大人の役目じゃありませんか？","ENG":"That’s why I have to teach these newbies so that they won’t end up dead.","TWN":"所以至少要幫助隊員們能夠自力更生，這樣才算是個成熟的大人嘛！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"하아, 호랑이도 제 말 하면 온다더니…","JPN":"はあ、噂をすればなんとやら……","ENG":"Speaking of the devil...","TWN":"哈哈，說曹操曹操到…"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"으, 으으… 팀장님? 혹시 지금 바쁘세요?","JPN":"あ、あの……チームリーダー。　ちょっといいですか？","ENG":"Huh...? Boss...? Are you busy right now...?","TWN":"呃…隊長？你在忙嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L41_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"심소미, 너 오늘 비번 아니었냐?","JPN":"ヒマワリさん、今日は非番のはずでは？","ENG":"Shim Somi, I thought you were taking the day off.","TWN":"沈小美，你今天不用值班嗎？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"네! 비번이기는 했는데요……!","JPN":"はいっ！　そうだったのですが……！","ENG":"Yes, I was!","TWN":"要！我今天要值班，只是……！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"5팀 팀장님이 현장직 부족하니까 도와달라고 하셔서 왔거든요!","JPN":"5チームのリーダーさんから、現場の手が足りないから手伝ってくれと頼まれまして！","ENG":"But the chief of Team 5 asked me to come, saying that they didn't have enough people in the field!","TWN":"第5隊隊長說現場人手不夠請我幫忙，所以我就來了！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아, 아무래도 저 혼자로는 조금! 아니, 많이 역부족이라서요!","JPN":"ちょ、ちょっと私一人じゃ少し……いや、めちゃくちゃ力不足で！","ENG":"Then I realized that I wasn’t good enough! Like, not good enough at all!","TWN":"可…可是光靠我一個人好像有點，不！是非常不行！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"차 팀장, 이 망할 놈이…….","JPN":"あのくそ野郎……","ENG":"Cha, that bastard...","TWN":"車隊長，那個該死的傢伙……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"좌표 보내. 강산이한테도 연락 보내고.","JPN":"座標を送ってください。それからツヨシにも連絡を。","ENG":"Send me the coordinates. Send them to Gangsan as well.","TWN":"把座標給我！也聯絡一下江山！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뒷정리는 맡겨야겠군. 먼저 가 봐야겠수다.","JPN":"後片付けをお願いできますか？　急用ができまして。","ENG":"I’m sorry I can’t help you clean this place up. I have to go now.","TWN":"我有事要先走了，這邊就再麻煩你整理囉！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그래요. 건투를 빌어 드리죠.","JPN":"ええ。健闘を祈ります。","ENG":"It’s okay. Good luck.","TWN":"沒問題，祝你們順利！"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"뭐, 어떻게든 될 거요. 차 팀장이 자기 팀 몫이라고 생떼 쓰지만 않는다면 말이지.","JPN":"ま、あの5チームのくそ野郎が変な意地さえ張らなければ、なんとかなるでしょう。","ENG":"Yes, I’ll be okay. Unless Cha tries to claim his share.","TWN":"順利是一定的啦，只要車隊長不要耍賴就好。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"아. 그렇지.","JPN":"あ、そうだ。","ENG":"Oh, and...","TWN":"喔，對了。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그 사람, 잘 챙겨 주고.","JPN":"あの人、ちゃんとケアしてあげてくださいね。","ENG":"Make sure you take care of that person.","TWN":"你要好好照顧那個人喔。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 사람이라뇨?","JPN":"あの人って？","ENG":"That person?","TWN":"哪個人？"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"댁이 말한 그 잘난 분 말이오.","JPN":"あなたの言っていたすごい方です。","ENG":"The real talent you mentioned.","TWN":"就是你剛剛說很厲害的那個人。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"지금 회사에서 오래 썩다 보니, 모난 돌이 정 맞는다는 소리가 왜 나왔는지 알게 됐거든.","JPN":"今の会社に長くいるうちに、出る杭は打たれるって言葉がなんでできたのか、わかるようになりましてね。","ENG":"I’ve been working at this company for a long time and realized that people hate those who stand out.","TWN":"公司已經腐敗這麼久，我終於見識到什麼是樹大招風，人紅招忌。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아무리 그래도 그런 실수를 하다니, 어른스럽지 않았어.","JPN":"いくらなんでもあんなミスをするなんて……大人気なかったわ。","ENG":"I shouldn’t have made such a mistake.","TWN":"竟然犯下那種失誤，真是太沉不住氣了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…어? 이진 언니?","JPN":"あら……？　ホノカさん？","ENG":"Oh, Jin!","TWN":"…嗯？李珍姐？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨? 이 시간에 여긴 어쩐 일이시죠?","JPN":"ユイお嬢様。　こんな時間にどうされました？","ENG":"Miss Jia? What are you doing here at this hour?","TWN":"小姐？這個時間你怎麼會在這裡？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 사무실에 가고 있어요.","JPN":"あ、事務所に行くところでした。","ENG":"Oh, I was on my way to the office.","TWN":"喔～我正要去辦公室的路上。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"본사에서 연락이 왔거든요. 저희가 작성한 부대 운영안이 아직 도착하지 않았다고요.","JPN":"本社から私たちが作成した部隊の運営案がまだ届いていないと連絡があったのです。","ENG":"HQ told me they hadn’t received our unit operation plan yet.","TWN":"因為總公司來消息說，我們的部隊經營方案還沒送到。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부대 운영안이라면 가브리엘한테 지난 주까지 정리해서 보내라고 했는데…","JPN":"部隊の運営案なら、ガブリエルにまとめて出すよう先週伝えておきましたが……","ENG":"I told Gabriel to finish the plan and send it to HQ last week...","TWN":"部隊經營方案嗎？我記得我請加布里埃爾上週整理好後寄出去…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"설마 이 녀석이 또!?","JPN":"まさか、また！？","ENG":"He must have missed it again...","TWN":"難道那個傢伙又？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아니, 그보다 그래서 이렇게 늦은 시간에 출근하신다고요?","JPN":"それよりも、そのためにこんな遅い時間に出勤されるのですか？","ENG":"But you’re going to the office now? It’s too late.","TWN":"不過，小姐是因為這樣，才會這麼晚還要去辦公室嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 할아버님께서 말씀하셨는걸요. 직원의 일도 자기 일처럼 생각하라고요.","JPN":"はい、お祖父様はこう言いました。部下の仕事も自分の仕事のように考えるべきだと。","ENG":"My grandfather said that your employee’s job is your job.","TWN":"是的，我爺爺有說，要把員工的事當成是自己的事。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지아 아가씨, 회장님께서 하셨던 말씀은 그저…….","JPN":"ユイお嬢様、会長の意図はただ……","ENG":"Miss Jia, what your grandfather meant was...","TWN":"小姐，會長的意思是……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 어차피 저 혼자 해도 금방 끝낼 수 있어요.","JPN":"心配しないでください。私一人でもすぐに片付きますから。","ENG":"Don’t worry about it. I can take care of it myself.","TWN":"沒關係的，反正我自己很快就可以弄完。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"정말로 더 나은 세상을 위해서라면…","JPN":"心からより良い世界を願うなら……","ENG":"If you really want a better world...","TWN":"要落實為了更好的未來…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그런 괴물부터 이 세상에서 없애 버려야 한다고.</color>","JPN":"<color=#ff3636>あの化け物を、この世から消し去るべきだ。</color>","ENG":"<color=#ff3636>You have to get rid of the monster first.</color>","TWN":"<color=#ff3636>就必須先把那個怪物從世界上除掉。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 저도 돕겠습니다. 아가씨만 사무실에 계시게 둘 수는 없죠.","JPN":"いいえ、私も手伝います。お嬢様一人だけ事務所に残すわけにはいきません。","ENG":"No, please let me help. I don’t want to leave you in the office by yourself.","TWN":"不，我也來幫忙吧。怎麼可以把小姐單獨留在辦公室呢！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"고마워요, 언니. 왠지 친구끼리 밤새 놀기로 한 거 같아서 가슴이 두근거려요.","JPN":"ありがとうございます、ホノカさん。なんだかお友だちと夜更かしするみたいで、わくわくします。","ENG":"Thank you. I'm so excited that it feels like a night out with a friend. ","TWN":"謝謝你，李珍姐。感覺好像和朋友一起玩通宵一樣，有點刺激的感覺。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아닙니다, 아가씨. 별말씀을요.","JPN":"……とんでもありません、お嬢様。","ENG":"You’re welcome, Miss Jia.","TWN":"……不會，小姐不用這麼客氣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};